static double MoyenneGenerale(double[,] notes)
{
    double somme = 0;
    int total = 0;
    for (int i = 0; i < notes.GetLength(0); i++)
    {
        for (int j = 0; j < notes.GetLength(1); j++)
        {
            somme += notes[i, j];
            total++;
        }
    }
    return somme / total;
}
