static int[,] AppliquerFiltreMoyenne(int[,] image)
{
    int lignes = image.GetLength(0);
    int colonnes = image.GetLength(1);
    int[,] resultat = new int[lignes, colonnes];

    for (int i = 0; i < lignes; i++)
    {
        for (int j = 0; j < colonnes; j++)
        {
            if (i == 0 || i == lignes - 1 || j == 0 || j == colonnes - 1)
            {
                resultat[i, j] = image[i, j]; // bord : on conserve la valeur
            }
            else
            {
                int somme = 0;
                for (int di = -1; di <= 1; di++)
                    for (int dj = -1; dj <= 1; dj++)
                        somme += image[i + di, j + dj];
                resultat[i, j] = (int)Math.Round(somme / 9.0);
            }
        }
    }
    return resultat;
}
